// Stap 1 + 2: leest 'mode' uit het webhook-body en bouwt per binary-PDF
// een Docling-item (base64). akte/beide: de HELE upload (alle PDF- en Word-bestanden) wordt verwerkt.
// Classificatie: precies één primaire bank-passeeropdracht, één of meer kadaster-stukken,
// overige bestanden = dossier (alleen mee naar juridische analyse, niet naar kadaster-extractie).
//
// Mode: 'akte' | 'beide' | 'analyse'

const webhookItem = $input.first();
const body = (webhookItem && webhookItem.json && webhookItem.json.body) || {};
const b = (webhookItem && webhookItem.binary) || {};
const keys = Object.keys(b);

const rawMode = String(body.mode || '').trim().toLowerCase();
// Onbekende mode-waarden NIET silently normaliseren naar 'beide': dan zou
// de Analyse Route fallback (P1.2) onbereikbaar blijven. Lege mode wordt
// wel default 'beide' (back-compat voor clients die geen mode meesturen).
// Mode Route ziet 'analyse' apart; alle andere (akte/beide/onbekend)
// gaan via de bank+kadaster-classificatie hieronder.
const mode = rawMode || 'beide';

if (keys.length === 0) {
  throw new Error(
    'Webhook ontving geen binary bestanden. Stuur PDF- of Word-bestanden (.docx) als multipart/form-data mee.'
  );
}

function isConvertibleDoc(k) {
  const fn = String(b[k]?.fileName || '').toLowerCase();
  const mime = String(b[k]?.mimeType || '').toLowerCase();
  if (fn.endsWith('.pdf') || mime.includes('pdf')) return true;
  if (fn.endsWith('.docx')) return true;
  if (mime.includes('wordprocessingml') || mime.includes('officedocument.wordprocessingml')) return true;
  return false;
}

const docKeys = keys.filter(isConvertibleDoc);
if (docKeys.length === 0) {
  throw new Error(
    'Geen ondersteunde documenten (PDF of .docx) in de upload.'
  );
}

async function loadAsBase64(binaryKey) {
  const buffer = await this.helpers.getBinaryDataBuffer(0, binaryKey);
  return buffer.toString('base64');
}

const base = {
  receivedAt: new Date().toISOString(),
  mode,
};

const BANK_RX_LEGACY = /passeer|nti|rabobank|abnamro|abn[\s_-]?amro|ing|obvion|munt|bank|stater/;
const KAD_RX_LEGACY = /eigendom|kadaster/;

function bankScore(fname) {
  const f = String(fname || '').toLowerCase();
  if (
    /passeerbevestig|passeergegevens|gelden\s+notaris|conceptnota|factuur|\bwwft\b|bankpas|definitieve\s+set|uitbetaling/i.test(f)
  ) {
    return -100;
  }
  let s = 0;
  if (/passeeropdracht/i.test(f)) s += 200;
  if (/notarisinstructie|voorlopige\s+gegevens/i.test(f)) s += 180;
  if (/rabobank|co[oö]peratieve\s+rabo|abn|abnamro|\bing\b|obvion|regiobank|florius|aegon|asr/i.test(f)) s += 85;
  if (/\bnti\b|nutsworth|stater/i.test(f)) s += 85;
  if (/\bpasseer\b/i.test(f) && !/bevestig|melding|gegevens/i.test(f)) s += 35;
  if (/voorlopig/i.test(f)) s -= 40;
  return s;
}

function isKadasterName(fname) {
  const f = String(fname || '').toLowerCase();
  if (/passeeropdracht|notarisinstructie/i.test(f)) return false;
  if (/passeerbevestig|\bwwft\b|\bfactuur\b|bankpas|uitbetaling|\.eml|conceptnota|nota\s+-/i.test(f)) {
    return false;
  }
  return /kadastraal|hypothecair|eigendom|kadaster|objectlijst|rechthebbende|brondocument|uittreksel|kadastrale\s+kaart|hypotheekakte|\bkik\b|\bhyp\d|onroerende\s+zaken|perceel/i.test(f);
}

if (mode === 'analyse') {
  const items = [];
  for (const k of docKeys) {
    const fname = String(b[k]?.fileName || '').toLowerCase();
    let docType = 'overig';
    if (bankScore(fname) >= 50) docType = 'bank';
    else if (isKadasterName(fname) || KAD_RX_LEGACY.test(fname)) docType = 'kadaster';
    const blob = await loadAsBase64.call(this, k);
    items.push({
      json: {
        ...base,
        docType,
        filename: b[k]?.fileName || `${k}.pdf`,
        base64_string: blob,
      },
    });
  }
  return items;
}

const scored = docKeys.map((k) => {
  const fname = String(b[k]?.fileName || k);
  return { key: k, fname, score: bankScore(fname), kad: isKadasterName(fname) };
});

let primary = null;
let best = -Infinity;
for (const row of scored) {
  if (row.score > best) {
    best = row.score;
    primary = row;
  }
}

const EXPLICIT_BANK = new Set(['passeeropdracht', 'bank', 'file_bank', 'passeeropdracht_0']);
for (const row of scored) {
  const lk = String(row.key || '').toLowerCase();
  if (EXPLICIT_BANK.has(lk)) {
    primary = row;
    best = 9999;
    break;
  }
}

if (!primary || best < 30) {
  const legacyBankKey = docKeys.find((k) =>
    BANK_RX_LEGACY.test(String(b[k]?.fileName || '').toLowerCase())
  );
  if (legacyBankKey) {
    primary = scored.find((s) => s.key === legacyBankKey) || {
      key: legacyBankKey,
      fname: String(b[legacyBankKey]?.fileName || ''),
      score: 50,
      kad: false,
    };
    best = primary.score;
  }
}

if (!primary || best < 30) {
  throw new Error(
    `Geen bank-passeeropdracht herkend in de upload (${docKeys.length} bestand(en)). ` +
      `Voeg de bank-passeeropdracht toe of gebruik een bestandsnaam met «passeeropdracht». ` +
      `Files: ${scored.map((r) => r.fname).join(', ')}`
  );
}

const primaryKey = primary.key;
const kadasterKeys = [];
for (const row of scored) {
  if (row.key === primaryKey) continue;
  if (row.kad || KAD_RX_LEGACY.test(row.fname.toLowerCase())) {
    kadasterKeys.push(row.key);
  }
}

if (kadasterKeys.length === 0) {
  const legacyKad = docKeys.find(
    (k) => k !== primaryKey && KAD_RX_LEGACY.test(String(b[k]?.fileName || '').toLowerCase())
  );
  if (legacyKad) kadasterKeys.push(legacyKad);
}

if (kadasterKeys.length === 0) {
  throw new Error(
    `Geen kadastrale documenten herkend. Voeg minstens één stuk toe (kadastraal/hypothecair/uittreksel/objectlijst). ` +
      `Files: ${scored.map((r) => r.fname).join(', ')}`
  );
}

const out = [];
for (const row of scored) {
  const k = row.key;
  const blob = await loadAsBase64.call(this, k);
  const fname = b[k]?.fileName || `${k}.pdf`;
  let docType;
  if (k === primaryKey) docType = 'bank';
  else if (kadasterKeys.includes(k)) docType = 'kadaster';
  else docType = 'dossier';
  out.push({
    json: {
      ...base,
      docType,
      filename: fname,
      base64_string: blob,
    },
  });
}

return out;

// Per Docling-response: pak de markdown en bewaar docType + mode + bestandsnaam.
const sourceItem = $('Split Input Files').itemMatching($itemIndex);
const docType = sourceItem?.json?.docType || $json.docType || 'overig';
const mode = sourceItem?.json?.mode || 'beide';
const filename = sourceItem?.json?.filename || '';

const payload = $json;
let md = '';
if (payload?.document?.md_content) md = payload.document.md_content;
else if (payload?.md_content) md = payload.md_content;
else if (payload?.result?.document?.md_content) md = payload.result.document.md_content;
else if (Array.isArray(payload?.documents) && payload.documents[0]?.md_content) md = payload.documents[0].md_content;

if (!md) {
  throw new Error(`Docling gaf geen md_content terug voor ${filename || docType}. Top-level keys: ${Object.keys(payload || {}).join(', ')}`);
}

return { json: { docType, mode, filename, markdown: md } };

// Analyse-flow (mode='analyse'): voegt alle aangeleverde markdowns samen tot
// één blok dat als één prompt aan de juridische-analyse-LLM gestuurd kan
// worden. Werkt voor 1..N PDFs.
const items = $input.all();
if (!items.length) {
  throw new Error('Geen markdowns ontvangen voor de analyse-flow.');
}

const MAX_PER_DOC = 12000;
function clamp(s, max) {
  const txt = String(s || '');
  if (txt.length <= max) return txt;
  return txt.slice(0, max) + '\n…[afgekapt voor analyse-prompt]';
}

function docTypeLabel(t) {
  if (t === 'bank') return 'Bank-passeeropdracht';
  if (t === 'kadaster') return 'Kadaster eigendomsinformatie';
  return 'Document';
}

const docs = items.map((it, i) => {
  const j = it.json || {};
  return {
    index: i + 1,
    docType: j.docType || 'overig',
    filename: j.filename || `document_${i + 1}.pdf`,
    markdown: clamp(j.markdown || '', MAX_PER_DOC)
  };
});

const klantNaam = '';
const now = new Date();
const zaaknummer = `${now.getFullYear()}${String(now.getMonth() + 1).padStart(2, '0')}${String(now.getDate()).padStart(2, '0')}_${String(now.getHours()).padStart(2, '0')}${String(now.getMinutes()).padStart(2, '0')}${String(now.getSeconds()).padStart(2, '0')}`;

const bankDocs = docs.filter((d) => d.docType === 'bank').map((d) => d.filename);
const bankDisplay = bankDocs.length
  ? `Onbekend (uit ${bankDocs.join(', ')})`
  : 'Onbekend';

return [{
  json: {
    mode: 'analyse',
    docs,
    documentCount: docs.length,
    zaaknummer,
    bankDisplayName: bankDisplay,
    klantSamenvatting: klantNaam
  }
}];

// Bouwt de prompt voor de juridische analyse in 'analyse-only'-mode.
// Documenten worden gesplitst op type zodat bank, kadaster en overige stukken
// (bijv. BRP-inzage) elk in de juiste placeholder terechtkomen.
const fs = require('fs');
const REGISTRY_PATH = '/data/shared/templates/registry.json';

// $json = output van Parse Burgerlijke Analyse JSON (bevat aggregate data).
// $('Aggregate Markdowns') als backup voor directe uitvoer zonder specialist.
let input = $json || {};
if (!Array.isArray(input.docs) || input.docs.length === 0) {
  try {
    const agg = $('Aggregate Markdowns').first()?.json;
    if (agg && Array.isArray(agg.docs) && agg.docs.length > 0) input = agg;
  } catch (_) {}
}
const docs = Array.isArray(input.docs) ? input.docs : [];

let registry;
try {
  registry = JSON.parse(fs.readFileSync(REGISTRY_PATH, 'utf8'));
} catch (err) {
  throw new Error(`Kon templates-registry niet lezen (${REGISTRY_PATH}): ${err.message}`);
}

const basePrompt = String(registry.flex_analysis_prompt || registry.legal_analysis_prompt || '');
if (!basePrompt) {
  throw new Error('registry.json mist legal_analysis_prompt.');
}

function docTypeLabel(t) {
  if (t === 'bank') return 'Bank-passeeropdracht';
  if (t === 'kadaster') return 'Kadaster eigendomsinformatie';
  return 'Aanvullend dossierstuk';
}

function buildBlocks(docList) {
  return docList.map((d, i) => {
    const label = docTypeLabel(d.docType);
    return `=== DOCUMENT ${i + 1} \u2014 ${label} \u2014 ${d.filename} ===\n${d.markdown}`;
  }).join('\n\n');
}

// Splits op type: bank, kadaster, overig (BRP-inzage, dossier e.d.)
const bankDocs     = docs.filter(d => d.docType === 'bank');
const kadasterDocs = docs.filter(d => d.docType === 'kadaster');
const overigDocs   = docs.filter(d => d.docType !== 'bank' && d.docType !== 'kadaster');

// {{bank_markdown}}: bank-docs als aanwezig; anders alle docs als fallback.
const bankBlocks = bankDocs.length > 0
  ? buildBlocks(bankDocs)
  : buildBlocks(docs);

// {{kadaster_markdown}}: kadaster-docs als aanwezig; anders melding.
const kadasterBlocks = kadasterDocs.length > 0
  ? buildBlocks(kadasterDocs)
  : '(geen apart kadasterstuk aangeleverd in dit dossier)';

// Overige stukken (BRP, gezinssamenstelling, etc.) als aparte sectie in
// {{extracted_json}} zodat de LLM ze als context gebruikt, niet als
// bank- of kadasterdocument.
const overigNote = overigDocs.length > 0
  ? '\n\n=== OVERIGE DOSSIERSTUKKEN (bijv. BRP-inzage, gezinssamenstelling) ===\n'
    + buildBlocks(overigDocs)
  : '';

const extractedNote = '(geen gestructureerde extractie beschikbaar in deze analyse-only-flow; '
  + 'baseer de beoordeling op de ruwe documenten hierboven)'
  + overigNote;

const chatInput = basePrompt
  .split('{{bank_markdown}}').join(bankBlocks)
  .split('{{kadaster_markdown}}').join(kadasterBlocks)
  .split('{{extracted_json}}').join(extractedNote);

return [{
  json: {
    chatInput,
    mode: 'analyse',
    zaaknummer: input.zaaknummer,
    bankDisplayName: input.bankDisplayName,
    klantSamenvatting: input.klantSamenvatting || '',
    documentCount: docs.length
  }
}];

// Parseert de juridische analyse JSON die de LLM teruggeeft (analyse-only-flow).
// Identieke logica als de 'beide'-flow, hier gedupliceerd om de routing
// eenvoudig te houden.
function extractText(j) {
  if (!j || typeof j !== 'object') return '';
  if (typeof j.text === 'string' && j.text) return j.text;
  if (typeof j.output === 'string' && j.output) return j.output;
  if (typeof j.answer === 'string' && j.answer) return j.answer;
  if (typeof j.response === 'string' && j.response) return j.response;
  if (typeof j?.message?.content === 'string' && j.message.content) return j.message.content;
  return '';
}
function unwrapJsonLike(s) {
  let t = String(s || '').trim();
  const fence = /^```(?:json)?\s*\r?\n?([\s\S]*?)\r?\n?```$/im;
  const m = t.match(fence);
  if (m) return m[1].trim();
  if (t.startsWith('```')) {
    t = t.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '');
  }
  return t.trim();
}
function parseAnalysis(jsonNode) {
  const raw = extractText(jsonNode).trim();
  if (raw) {
    try { const _p = JSON.parse(unwrapJsonLike(raw)); if (!Array.isArray(_p)) return _p; } catch {}
    const m = raw.match(/\{[\s\S]*\}/);
    if (m) {
      try { return JSON.parse(m[0]); } catch {}
    }
  }
  const META = new Set(['pairedItem', 'sourceData', '$node']);
  const obj = {};
  for (const k of Object.keys(jsonNode || {})) {
    if (!META.has(k) && !k.startsWith('_')) obj[k] = jsonNode[k];
  }
  if ('aandachtspunten' in obj || 'samenvatting' in obj) return obj;
  return null;
}

const all = $input.all();
const node = all[0]?.json || {};
let parsed = parseAnalysis(node);

if (!parsed || typeof parsed !== 'object') {
  parsed = { samenvatting: '', aandachtspunten: [] };
}

const WRAPPER_KEYS = new Set(['analyse', 'analysis', 'data', 'response', 'result', 'output']);
let depth = 0;
while (
  parsed && typeof parsed === 'object' && !Array.isArray(parsed) &&
  Object.keys(parsed).length === 1 &&
  WRAPPER_KEYS.has(Object.keys(parsed)[0]) && depth < 3
) {
  parsed = parsed[Object.keys(parsed)[0]];
  depth++;
}

const aandacht = Array.isArray(parsed.aandachtspunten) ? parsed.aandachtspunten : [];
const ALLOWED = new Set(['kritiek', 'aandacht', 'info']);
const ALIASES = { critical: 'kritiek', blokkerend: 'kritiek', warning: 'aandacht', warn: 'aandacht', notice: 'info', informatief: 'info' };
const normalised = aandacht.map((ap, i) => {
  const e = String(ap?.ernst || '').trim().toLowerCase();
  const ernst = ALLOWED.has(e) ? e : (ALIASES[e] || 'info');
  return {
    id: String(ap?.id || `punt-${i + 1}`),
    ernst,
    categorie: String(ap?.categorie || 'Overig'),
    titel: String(ap?.titel || '').slice(0, 160),
    constatering: String(ap?.constatering || ''),
    juridisch_kader: String(ap?.juridisch_kader || ''),
    actie: String(ap?.actie || ''),
    bronnen: Array.isArray(ap?.bronnen) ? ap.bronnen.map(String) : []
  };
});
const ORDER = { kritiek: 0, aandacht: 1, info: 2 };
normalised.sort((a, b) => (ORDER[a.ernst] ?? 9) - (ORDER[b.ernst] ?? 9));

const samenvatting = String(parsed.samenvatting || '').trim();

// Merge burgerlijke-specialist-bevindingen.
// Parse Burgerlijke Analyse JSON is een directe voorouder (via Build Flex
// Analysis Prompt) — $() is hier betrouwbaar.
let burgerlijkeItems = [];
try {
  const bNode = $('Parse Burgerlijke Analyse JSON').first()?.json;
  if (Array.isArray(bNode?.burgerlijke_aandachtspunten)) {
    burgerlijkeItems = bNode.burgerlijke_aandachtspunten;
  }
} catch (e) {
  // Log voor debuggen — nooit silent falen op kritieke merge
  console.error('[Parse Flex Analysis JSON] burgerlijke merge fout:', e?.message);
}

const heeftSpecialist = burgerlijkeItems.length > 0;
const filteredNorm = heeftSpecialist
  ? normalised.filter(ap => String(ap?.categorie || '').toLowerCase() !== 'burgerlijke staat')
  : normalised;

const seenM = new Set();
const merged = [];
for (const ap of [...burgerlijkeItems, ...filteredNorm]) {
  const id = String(ap?.id || '').trim();
  if (id && seenM.has(id)) continue;
  if (id) seenM.add(id);
  merged.push(ap);
}
const ORDER_M = { kritiek: 0, aandacht: 1, info: 2 };
merged.sort((a, b) => (ORDER_M[a.ernst] ?? 9) - (ORDER_M[b.ernst] ?? 9));

return [{
  json: {
    analysis: {
      samenvatting,
      aandachtspunten: merged
    },
    counts: {
      kritiek: merged.filter((x) => x.ernst === 'kritiek').length,
      aandacht: merged.filter((x) => x.ernst === 'aandacht').length,
      info: merged.filter((x) => x.ernst === 'info').length,
      totaal: merged.length
    }
  }
}];

// Args naar tijdelijk JSON-bestand schrijven voor genereer_juridische_analyse.py
// (analyse-only flow). Python-script verwijdert het bestand na inlezen.
const fs = require('fs');
const execId = String($execution.id || 'single').replace(/[^0-9A-Za-z_-]/g, '_').slice(0, 32);
const argsFile = `/tmp/n8n_args_flex_analyse_${execId}_${Date.now()}.json`;
const meta = $('Aggregate Markdowns').first()?.json || {};
const j = $json || {};
const payload = {
  analysis: j.analysis || {},
  zaaknummer: String(meta.zaaknummer || ''),
  bank: String(meta.bankDisplayName || ''),
  klant: String(meta.klantSamenvatting || ''),
};
fs.writeFileSync(argsFile, JSON.stringify(payload), 'utf8');
return { json: { ...j, argsFile } };

// Bouwt de webhook-respons voor de analyse-only-flow.
const analysisCmdNode = $('Generate Flex Analysis DOCX').first()?.json || {};
const analysisCmdStdout = String(analysisCmdNode.stdout || '');
const analysisCmdErr = String(analysisCmdNode.stderr || '');
const analysisMatch = analysisCmdStdout.match(/SUCCESS:\s*(.+)/);
const analysisPath = analysisMatch ? analysisMatch[1].trim() : '';
const analysisFilename = analysisPath ? analysisPath.split('/').pop() : '';

const analysisDataNode = $('Parse Flex Analysis JSON').first()?.json || {};
const analysis = analysisDataNode.analysis || { samenvatting: '', aandachtspunten: [] };
const counts = analysisDataNode.counts || {
  kritiek: 0, aandacht: 0, info: 0,
  totaal: (analysis.aandachtspunten || []).length
};

const meta = $('Aggregate Markdowns').first()?.json || {};

return [{
  json: {
    success: true,
    mode: 'analyse',
    filename: null,
    file_path: null,
    download_url: null,
    bank_id: null,
    bank_display_name: meta.bankDisplayName || null,
    klant_samenvatting: meta.klantSamenvatting || '',
    zaaknummer: meta.zaaknummer || '',
    document_count: meta.documentCount || 0,
    analysis: {
      ...analysis,
      counts,
      filename: analysisFilename || null,
      file_path: analysisPath || null,
      download_url: analysisFilename ? `http://localhost:8080/output/${analysisFilename}` : null,
      generation_warning: !analysisPath
        ? `Analyse-DOCX niet gegenereerd. stdout=${analysisCmdStdout.slice(0, 200)}; stderr=${analysisCmdErr.slice(0, 200)}`
        : null
    }
  }
}];

// Bepaalt voor de bank-doc welke bank het is op basis van keywords in de
// registry, en bouwt vervolgens de juiste extractie-prompt voor de LLM.
// Voor de kadaster-doc gebruikt het de generieke kadaster-prompt.
const fs = require('fs');
const REGISTRY_PATH = '/data/shared/templates/registry.json';

let registry;
try {
  registry = JSON.parse(fs.readFileSync(REGISTRY_PATH, 'utf8'));
} catch (err) {
  throw new Error(`Kon templates-registry niet lezen (${REGISTRY_PATH}): ${err.message}`);
}

const banks = registry.banks || {};
const kadasterPrompt = registry.kadaster_extraction_prompt || '';

const docType = $json.docType;
const markdown = String($json.markdown || '');

function renderPrompt(template, md) {
  return String(template || '').split('{{markdown}}').join(md);
}

const dossier_markdown = String($json.dossier_markdown || '');

if (docType === 'kadaster') {
  if (!kadasterPrompt) {
    throw new Error('registry.json mist kadaster_extraction_prompt.');
  }
  return {
    json: {
      docType,
      bankId: null,
      markdown,
      dossier_markdown,
      chatInput: renderPrompt(kadasterPrompt, markdown)
    }
  };
}

const lower = markdown.toLowerCase();
let detectedBankId = null;
let bestScore = 0;

for (const [bankId, bank] of Object.entries(banks)) {
  const keywords = bank.keywords || [];
  let score = 0;
  for (const kw of keywords) {
    if (lower.includes(String(kw).toLowerCase())) score++;
  }
  if (score > bestScore) {
    bestScore = score;
    detectedBankId = bankId;
  }
}

if (!detectedBankId) {
  const knownBanks = Object.keys(banks).join(', ') || '(geen)';
  throw new Error(
    `Geen bank kunnen herkennen uit de passeeropdracht. ` +
    `Bekende banken in registry: ${knownBanks}. ` +
    `Vraag een ontwikkelaar om deze bank toe te voegen aan registry.json.`
  );
}

const bankConfig = banks[detectedBankId];
if (!bankConfig.extraction_prompt) {
  throw new Error(`Bank '${detectedBankId}' heeft geen extraction_prompt in registry.`);
}

return {
  json: {
    docType,
    bankId: detectedBankId,
    markdown,
    dossier_markdown,
    chatInput: renderPrompt(bankConfig.extraction_prompt, markdown)
  }
};

// Parseert de LLM-output per document (bank óf kadaster) tot een platte
// structuur. Geen workflow-static-state meer: de daadwerkelijke combinatie
// van bank+kadaster gebeurt in de Aggregate-node 'Combine Bank+Kadaster'
// hierna. Daardoor blokkeert een failure in één tak niet meer een latere
// run (geen lekkende globale accumulator).
const promptItem = $('Build Extraction Prompt').itemMatching($itemIndex);
const docType = promptItem?.json?.docType;
const bankId = promptItem?.json?.bankId;
const markdown = String(promptItem?.json?.markdown || '');
const dossier_markdown = String(promptItem?.json?.dossier_markdown || '');

function extractText(j) {
  if (!j || typeof j !== 'object') return '';
  if (typeof j.text === 'string' && j.text) return j.text;
  if (typeof j.output === 'string' && j.output) return j.output;
  if (typeof j.answer === 'string' && j.answer) return j.answer;
  if (typeof j.response === 'string' && j.response) return j.response;
  const gen = j?.response?.generations;
  if (Array.isArray(gen) && gen.length) {
    const first = gen[0];
    if (Array.isArray(first) && first.length) {
      const t = first[0]?.text;
      if (typeof t === 'string' && t) return t;
      const c = first[0]?.message?.content;
      if (typeof c === 'string' && c) return c;
    } else if (first && typeof first === 'object') {
      if (typeof first.text === 'string' && first.text) return first.text;
    }
  }
  if (typeof j?.message?.content === 'string' && j.message.content) return j.message.content;
  if (Array.isArray(j?.message?.content)) {
    const chunks = [];
    for (const p of j.message.content) {
      if (typeof p === 'string') chunks.push(p);
      else if (p && typeof p.text === 'string') chunks.push(p.text);
    }
    if (chunks.length) return chunks.join('');
  }
  return '';
}

function unwrapJsonLike(s) {
  let t = String(s || '').trim();
  const fence = /^```(?:json)?\s*\r?\n?([\s\S]*?)\r?\n?```$/im;
  const m = t.match(fence);
  if (m) return m[1].trim();
  if (t.startsWith('```')) {
    t = t.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '');
  }
  if (t.startsWith('"""')) {
    t = t.replace(/^"""\s*(?:json)?\s*/i, '').replace(/\s*"""\s*$/i, '');
  }
  return t.trim();
}

function extractFirstJsonObject(s) {
  const str = String(s);
  const start = str.indexOf('{');
  if (start < 0) return null;
  let depth = 0;
  let inStr = false;
  let esc = false;
  for (let i = start; i < str.length; i++) {
    const c = str[i];
    if (inStr) {
      if (esc) { esc = false; continue; }
      if (c === '\\') { esc = true; continue; }
      if (c === '"') inStr = false;
      continue;
    }
    if (c === '"') { inStr = true; continue; }
    if (c === '{') depth++;
    else if (c === '}') {
      depth--;
      if (depth === 0) return str.slice(start, i + 1);
    }
  }
  return null;
}

function tryParseJson(raw) {
  const u = unwrapJsonLike(raw);
  try { return JSON.parse(u); } catch (_) {
    const cand = extractFirstJsonObject(u) || extractFirstJsonObject(raw);
    if (cand) { try { return JSON.parse(cand); } catch (_) {} }
  }
  return null;
}

let parsed = null;
const raw = extractText($json).trim();

if (raw) {
  parsed = tryParseJson(raw);
  if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) {
    throw new Error(
      `LLM output geen parsebare JSON voor ${docType}: ${raw.slice(0, 500)}`
    );
  }
} else {
  const META = new Set(['pairedItem', 'sourceData', '$node']);
  const obj = {};
  for (const k of Object.keys($json || {})) {
    if (!META.has(k) && !k.startsWith('_')) obj[k] = $json[k];
  }
  if (Object.keys(obj).length === 0) {
    throw new Error(
      `Lege LLM output voor ${docType}. Top-level keys: ${Object.keys($json || {}).join(', ')}`
    );
  }
  parsed = obj;
}

const WRAPPER_KEYS = new Set(['document', 'documents', 'data', 'response', 'result', 'output', 'json', 'extraction', 'fields']);
let unwrapDepth = 0;
while (
  parsed && typeof parsed === 'object' && !Array.isArray(parsed) &&
  Object.keys(parsed).length === 1 &&
  WRAPPER_KEYS.has(Object.keys(parsed)[0]) &&
  unwrapDepth < 3
) {
  const inner = parsed[Object.keys(parsed)[0]];
  if (inner && typeof inner === 'object' && !Array.isArray(inner)) {
    parsed = inner;
    unwrapDepth++;
  } else {
    break;
  }
}

return {
  json: {
    docType,
    bankId: bankId || null,
    parsed,
    markdown,
    dossier_markdown,
  }
};

// Bouwt placeholder-map declaratief op basis van de bank-specifieke mapping in
// registry.json. Elke placeholder-tag heeft een lijst met paden in de
// geëxtraheerde data; eerste niet-lege match wordt gebruikt. Voor banken met
// een `conditional_blocks`-config worden bovendien <<#FLAG:NAAM>>-keys
// toegevoegd die door vul_template_in.py gebruikt worden om hele blokken in
// of uit het template te schakelen.
//
// Input: één item met `docs` = [{ docType:'bank', parsed, bankId, markdown },
//                                { docType:'kadaster', parsed, markdown }]
// (geproduceerd door 'Combine Bank+Kadaster' Aggregate-node).
const fs = require('fs');
const REGISTRY_PATH = '/data/shared/templates/registry.json';

const j = $json || {};
const docs = Array.isArray(j.docs) ? j.docs : [];
const bankDoc = docs.find((d) => d && d.docType === 'bank');
const kadDoc = docs.find((d) => d && d.docType === 'kadaster');
if (!bankDoc) {
  throw new Error('Geen bank-document gevonden in samengevoegde Aggregate-input.');
}
if (!kadDoc) {
  throw new Error('Geen kadaster-document gevonden in samengevoegde Aggregate-input.');
}

const bank = bankDoc.parsed || {};
const kadaster = kadDoc.parsed || {};
const bankId = bankDoc.bankId;
const bank_markdown = String(bankDoc.markdown || '');
const kadaster_markdown = String(kadDoc.markdown || '');

if (!bankId) {
  throw new Error('Geen bankId beschikbaar — kon de bank niet detecteren in de bank-doc.');
}

let registry;
try {
  registry = JSON.parse(fs.readFileSync(REGISTRY_PATH, 'utf8'));
} catch (err) {
  throw new Error(`Kon templates-registry niet lezen (${REGISTRY_PATH}): ${err.message}`);
}

const bankConfig = (registry.banks || {})[bankId];
if (!bankConfig) {
  throw new Error(`Bank '${bankId}' niet gevonden in registry.json`);
}
if (!bankConfig.template_filename) {
  throw new Error(`Bank '${bankId}' heeft geen template_filename in registry.`);
}

const data = { bank, kadaster };

function getPath(obj, path) {
  const parts = String(path).split(/\.|\[|\]/).filter(Boolean);
  let cur = obj;
  for (const part of parts) {
    if (cur == null) return undefined;
    const idx = /^\d+$/.test(part) ? parseInt(part, 10) : part;
    cur = cur[idx];
  }
  return cur;
}

function isTruthyValue(v) {
  if (v == null) return false;
  if (typeof v === 'boolean') return v;
  if (typeof v === 'number') return v !== 0;
  const s = String(v).trim().toLowerCase();
  if (!s) return false;
  return ['true', '1', 'yes', 'ja', 'y', 't'].includes(s);
}

const placeholderMap = bankConfig.placeholders || {};
const placeholders = {};
for (const [tag, paths] of Object.entries(placeholderMap)) {
  let value = '';
  const candidatePaths = Array.isArray(paths) ? paths : [paths];
  for (const p of candidatePaths) {
    const v = getPath(data, p);
    if (v != null && String(v).trim() !== '') {
      value = String(v);
      break;
    }
  }
  placeholders[tag] = value;
}

const conditionalBlocks = bankConfig.conditional_blocks || {};
for (const [blockName, paths] of Object.entries(conditionalBlocks)) {
  const candidatePaths = Array.isArray(paths) ? paths : [paths];
  let active = false;
  for (const p of candidatePaths) {
    const v = getPath(data, p);
    if (typeof v === 'boolean') { active = v; if (v) break; continue; }
    if (v != null && String(v).trim() !== '') {
      const s = String(v).trim().toLowerCase();
      if (['true', 'false', '1', '0', 'yes', 'no', 'ja', 'nee'].includes(s)) {
        if (isTruthyValue(v)) { active = true; break; }
      } else {
        active = true;
        break;
      }
    }
  }
  placeholders[`<<#FLAG:${blockName}>>`] = active ? 'true' : 'false';
}

const ZAAKNUMMER_TAGS = ['<<ECH_ZAAKNUMMER>>', '<<OFFERTENUMMER>>'];
let zaaknummer = '';
for (const tag of ZAAKNUMMER_TAGS) {
  const v = String(placeholders[tag] || '').trim();
  if (v) { zaaknummer = v; break; }
}
if (!zaaknummer) {
  zaaknummer = String(Date.now());
  for (const tag of ZAAKNUMMER_TAGS) {
    if (tag in placeholders && !placeholders[tag]) {
      placeholders[tag] = zaaknummer;
      break;
    }
  }
}

function firstNonEmpty(...vals) {
  for (const v of vals) {
    if (v != null && String(v).trim() !== '') return String(v).trim();
  }
  return '';
}
const klanten = Array.isArray(kadaster?.klanten) ? kadaster.klanten
  : Array.isArray(bank?.klanten) ? bank.klanten : [];
const klantNamen = klanten
  .map((k) => firstNonEmpty(k?.naam_hoofdletters, k?.volledige_naam, k?.initialen_naam))
  .filter(Boolean);
const klantSamenvatting = klantNamen.length
  ? klantNamen.slice(0, 3).join(' / ')
  : '';

const templatePath = `/data/shared/templates/${bankId}/${bankConfig.template_filename}`;

return {
  json: {
    bankId,
    bankDisplayName: bankConfig.display_name || bankId,
    zaaknummer,
    templatePath,
    placeholders,
    klantSamenvatting,
    analysisInput: {
      bank_markdown,
      kadaster_markdown: (() => {
        // dossier_markdown komt nu mee in de Aggregate-input (vroeger
        // via $getWorkflowStaticData('global').dossierExtraMarkdownByExec).
        const extra = String(
          (bankDoc && bankDoc.dossier_markdown) ||
          (kadDoc && kadDoc.dossier_markdown) || ''
        ).trim();
        const core = kadaster_markdown;
        if (!extra) return core;
        return `${core}\n\n=== Overige dossier-PDFs (geen onderdeel van kadaster-extractie) ===\n${extra}`;
      })(),
      extracted: { bank, kadaster }
    },
    debug: {
      bank,
      kadaster
    }
  }
};

// Deterministische juridische checks op de geëxtraheerde data van
// passeeropdracht (bank) en kadaster. Levert aandachtspunten in dezelfde
// shape op als de LLM-analyse zodat de Parse-stap ze samen kan voegen.
//
// Wat deze node WEL doet (100% betrouwbaar, geen LLM):
//   1. Klantentelling: aantal schuldenaren ↔ aantal rechthebbenden
//   2. Achternaam-mismatch per klant (op volgorde gepaard)
//   3. Onderpand-gemeente vs. kadastrale gemeente
//
// Wat deze node NIET doet: bedragen-arithmetiek (die volgt 1-op-1 uit de
// passeeropdracht en heeft geen juridische waarde — eventueel als
// extractie-QA in een aparte stap).
//
// Output:
//   { ...alle velden van Build Placeholders..., deterministic_aandachtspunten: [...] }

const src = $json || {};
const extracted = (src.analysisInput && src.analysisInput.extracted) || (src.debug || {}) || {};
const bank = extracted.bank || {};
const kadaster = extracted.kadaster || {};
const bankKlanten = Array.isArray(bank.klanten) ? bank.klanten : [];
const kadKlanten = Array.isArray(kadaster.klanten) ? kadaster.klanten : [];

function stripAccents(s) {
  return String(s || '').normalize('NFKD').replace(/[\u0300-\u036f]/g, '');
}
function normName(s) {
  return stripAccents(s).toLowerCase().replace(/[^a-z]/g, '');
}
function normWord(s) {
  return stripAccents(s).toLowerCase().replace(/[^a-z0-9]/g, '');
}
function lastSurnameToken(s) {
  const cleaned = String(s || '')
    .replace(/[,.;]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
  if (!cleaned) return '';
  // Pak het laatste woord — bij dubbele achternamen ('Schmidt-de Klerk')
  // levert dat 'Klerk' op, wat als anker voor mismatch volstaat.
  const parts = cleaned.split(' ').filter(Boolean);
  return normName(parts[parts.length - 1] || '');
}
function bestName(klant) {
  return (
    klant?.naam_hoofdletters ||
    klant?.volledige_naam ||
    klant?.naam ||
    klant?.initialen_naam ||
    ''
  );
}

const aandachtspunten = [];

// --- 1. Klantentelling --------------------------------------------------
if (bankKlanten.length > 0 && kadKlanten.length > 0 && bankKlanten.length !== kadKlanten.length) {
  aandachtspunten.push({
    id: 'klantentelling-mismatch',
    ernst: 'kritiek',
    categorie: 'Identiteit',
    titel: 'Aantal schuldenaren wijkt af van aantal rechthebbenden',
    constatering: `Passeeropdracht noemt ${bankKlanten.length} schuldena(a)r(en); Kadaster vermeldt ${kadKlanten.length} rechthebbende(n).`,
    juridisch_kader: 'Schuldenaren in de hypotheekakte moeten in beginsel gelijk zijn aan de rechthebbenden op het onderpand. Afwijking duidt op (gelijktijdige) overdracht, vererving of een ontbrekende partij.',
    actie: 'Verifieer of een eigendomsoverdracht (koopakte) gelijktijdig passeert, of dat een rechthebbende ontbreekt in een van de stukken.',
    bronnen: ['passeeropdracht', 'kadaster']
  });
}

// --- 2. Achternaam-mismatch per klantpositie ---------------------------
const pairs = Math.min(bankKlanten.length, kadKlanten.length);
for (let i = 0; i < pairs; i++) {
  const bRaw = bestName(bankKlanten[i]);
  const kRaw = bestName(kadKlanten[i]);
  const bLast = lastSurnameToken(bRaw);
  const kLast = lastSurnameToken(kRaw);
  if (!bLast || !kLast) continue;
  if (bLast === kLast) continue;
  // Soft-match: 'klerk' in 'schmidtdeklerk' of andersom (dubbele achternaam)
  if (bLast.includes(kLast) || kLast.includes(bLast)) continue;
  aandachtspunten.push({
    id: `naam-mismatch-klant-${i + 1}`,
    ernst: 'kritiek',
    categorie: 'Identiteit',
    titel: `Achternaam klant ${i + 1} verschilt tussen bank en kadaster`,
    constatering: `Passeeropdracht: "${bRaw}". Kadaster: "${kRaw}". Achternamen komen niet overeen.`,
    juridisch_kader: 'De rechthebbende op het onderpand moet de hypotheek vestigen. Naamverschil kan duiden op recente naamswijziging (huwelijk/echtscheiding), vererving, of een geplande eigendomsoverdracht.',
    actie: 'Vergelijk met BRP/legitimatie. Vraag indien nodig verklaring van erfrecht, koopakte of huwelijksakte op.',
    bronnen: ['passeeropdracht', 'kadaster']
  });
}

// --- 3. Onderpand-gemeente vs. kadastrale gemeente --------------------
const bankWoon = normWord(bank.onderpand_woonplaats);
const kadGem = normWord(kadaster.kadastrale_gemeente);
if (bankWoon && kadGem && bankWoon !== kadGem && !bankWoon.includes(kadGem) && !kadGem.includes(bankWoon)) {
  aandachtspunten.push({
    id: 'onderpand-gemeente-mismatch',
    ernst: 'aandacht',
    categorie: 'Onderpand',
    titel: 'Onderpand-woonplaats wijkt af van kadastrale gemeente',
    constatering: `Passeeropdracht onderpand-woonplaats: "${bank.onderpand_woonplaats || ''}". Kadastrale gemeente: "${kadaster.kadastrale_gemeente || ''}".`,
    juridisch_kader: 'Het in de akte op te nemen onderpand moet ondubbelzinnig overeenkomen met het kadastrale perceel. Een verschil tussen woonplaats en kadastrale gemeente kan duiden op gemeentelijke herindeling — of op een verkeerd perceel.',
    actie: 'Verifieer of woonplaats en kadastrale gemeente werkelijk hetzelfde perceel betreffen (gemeentelijke herindeling toegestaan; verkeerd perceel niet).',
    bronnen: ['passeeropdracht', 'kadaster']
  });
}

// Passthrough alle Build-Placeholders-velden + deterministic_aandachtspunten
return {
  json: {
    ...src,
    deterministic_aandachtspunten: aandachtspunten
  }
};

// Schrijft de Python-argumenten naar een tijdelijk JSON-bestand zodat
// executeCommand geen payload-data hoeft te interpoleren via single-quotes.
// Voorkomt shell-injection bij apostrofs of quotes in zaaknummer/klant/etc.
// vul_template_in.py verwijdert het bestand na inlezen (best-effort cleanup).
const fs = require('fs');
const execId = String($execution.id || 'single').replace(/[^0-9A-Za-z_-]/g, '_').slice(0, 32);
const argsFile = `/tmp/n8n_args_akte_${execId}_${Date.now()}.json`;
const j = $json || {};
const payload = {
  template: j.templatePath,
  placeholders: j.placeholders,
  zaaknummer: String(j.zaaknummer || ''),
};
fs.writeFileSync(argsFile, JSON.stringify(payload), 'utf8');
return { json: { ...j, argsFile } };

// Bouwt de prompt voor de juridische analyse op basis van
// registry.legal_analysis_prompt. Vult drie placeholders:
//   {{bank_markdown}}, {{kadaster_markdown}}, {{extracted_json}}
// We knippen de markdowns op een veilige max-lengte zodat het lokale Ollama-
// contextvenster niet overstroomt.
const fs = require('fs');
const REGISTRY_PATH = '/data/shared/templates/registry.json';

const placeholdersItem = $('Build Placeholders').first();
const meta = placeholdersItem?.json || {};
const input = meta.analysisInput || {};

let registry;
try {
  registry = JSON.parse(fs.readFileSync(REGISTRY_PATH, 'utf8'));
} catch (err) {
  throw new Error(`Kon templates-registry niet lezen (${REGISTRY_PATH}): ${err.message}`);
}

const tmpl = String(registry.legal_analysis_prompt || '');
if (!tmpl) {
  throw new Error('registry.json mist legal_analysis_prompt.');
}

function clamp(s, max) {
  const txt = String(s || '');
  if (txt.length <= max) return txt;
  return txt.slice(0, max) + '\n…[afgekapt voor analyse-prompt]';
}

const limits = (registry && registry.context_limits) || {};
const MAX_BANK = Number(limits.analysis_bank) || 14000;
const MAX_KAD = Number(limits.analysis_kadaster) || 14000;
const MAX_EXTRACTED = Number(limits.analysis_extracted_json) || 8000;
const bankMd = clamp(input.bank_markdown, MAX_BANK);
const kadMd = clamp(input.kadaster_markdown, MAX_KAD);
const extracted = JSON.stringify(input.extracted || {}, null, 2);

const chatInput = tmpl
  .split('{{bank_markdown}}').join(bankMd)
  .split('{{kadaster_markdown}}').join(kadMd)
  .split('{{extracted_json}}').join(clamp(extracted, MAX_EXTRACTED));

return {
  json: {
    chatInput,
    bankId: meta.bankId,
    bankDisplayName: meta.bankDisplayName,
    zaaknummer: meta.zaaknummer,
    klantSamenvatting: meta.klantSamenvatting || ''
  }
};

// Bouwt de prompt voor de Vererving-specialist op basis van
// registry.legal_specialist_prompts.vererving. Vult één placeholder:
//   {{kadaster_markdown}}
//
// Heuristisch voorfilter (regex): alleen wanneer de Kadaster-tekst zelf één
// of meer vererving-signalen bevat, sturen we de LLM een echte analyse-vraag.
// Anders krijgt de LLM een ultrakorte instructie die altijd een lege array
// teruggeeft, en negeert de Parse-stap die output sowieso. Dit voorkomt
// false positives op een 3B-model dat anders te creatief is.
const fs = require('fs');
const REGISTRY_PATH = '/data/shared/templates/registry.json';

const placeholdersItem = $('Build Placeholders').first();
const meta = placeholdersItem?.json || {};
const input = meta.analysisInput || {};

let registry;
try {
  registry = JSON.parse(fs.readFileSync(REGISTRY_PATH, 'utf8'));
} catch (err) {
  throw new Error(`Kon templates-registry niet lezen (${REGISTRY_PATH}): ${err.message}`);
}

const tmpl = String(registry.legal_specialist_prompts?.vererving || '');
if (!tmpl) {
  throw new Error('registry.json mist legal_specialist_prompts.vererving.');
}

function clamp(s, max) {
  const txt = String(s || '');
  if (txt.length <= max) return txt;
  return txt.slice(0, max) + '\n…[afgekapt voor vererving-prompt]';
}

const limits = (registry && registry.context_limits) || {};
const MAX_MD = Number(limits.specialist_vererving) || 14000;
const kadMdFull = String(input.kadaster_markdown || '');
const kadMd = clamp(kadMdFull, MAX_MD);

// --- Regex pre-filter ---------------------------------------------------
// Patronen die specifiek wijzen op vererving/overlijden. Bewust restrictief
// om false hits te vermijden — bv. 'overdrach' is NIET genoeg (overdracht is
// een gewone levering).
const PATTERNS = [
  /(?:^|\b)overled(?:en|\.)/i,
  /†/,
  /verklaring\s+van\s+erfrecht/i,
  /akte\s+van\s+verdeling/i,
  /\b(?:weduwe|weduwnaar)\b/i,
  /onverdeelde\s+nalatenschap/i,
  /(?:sterfdatum|datum\s+van\s+overlijden)/i,
  /wettelijke\s+verdeling/i,
  /(?:saisine|art\.?\s*4:182)/i
];

const hits = [];
for (const re of PATTERNS) {
  const m = kadMdFull.match(re);
  if (m) hits.push(m[0]);
}
const signalCount = hits.length;

let chatInput;
if (signalCount > 0) {
  chatInput = tmpl.split('{{kadaster_markdown}}').join(kadMd);
} else {
  // Geen signalen: korte instructie. De Parse-stap negeert deze output
  // sowieso (op basis van signal_count==0), maar we sturen toch iets zinnigs
  // voor het geval iemand de LLM-output handmatig bekijkt.
  chatInput = 'Het bijgevoegde kadasterfragment bevat geen indicaties van vererving, overlijden, verklaring van erfrecht of een onverdeelde nalatenschap. Geef ALLEEN deze JSON terug, niets anders:\n{"aandachtspunten": []}';
}

return {
  json: {
    chatInput,
    signal_count: signalCount,
    signal_hits: hits.slice(0, 5),
    bankId: meta.bankId,
    bankDisplayName: meta.bankDisplayName,
    zaaknummer: meta.zaaknummer
  }
};

// Parseert de output van de Vererving-specialist. Werkt zowel met geldige
// JSON via format=json als met tekst inclusief eventuele markdown-fences.
// Forceert categorie='Vererving' (specialist mag dat veld niet veranderen)
// en bronnen=['kadaster'].
function extractText(j) {
  if (!j || typeof j !== 'object') return '';
  if (typeof j.text === 'string' && j.text) return j.text;
  if (typeof j.output === 'string' && j.output) return j.output;
  if (typeof j.answer === 'string' && j.answer) return j.answer;
  if (typeof j.response === 'string' && j.response) return j.response;
  if (typeof j?.message?.content === 'string' && j.message.content) return j.message.content;
  return '';
}
function unwrapJsonLike(s) {
  let t = String(s || '').trim();
  const fence = /^```(?:json)?\s*\r?\n?([\s\S]*?)\r?\n?```$/im;
  const m = t.match(fence);
  if (m) return m[1].trim();
  if (t.startsWith('```')) {
    t = t.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '');
  }
  return t.trim();
}
function parseSpec(node) {
  const raw = extractText(node).trim();
  if (raw) {
