    return doss.slice(0, max - 80) + '\n…[afgekapte dossiermarkdown]';
  }

  const headAvail = Math.max(0, max - doss.length);
  if (prefix.length > headAvail - 112) {
    prefix =
      prefix.slice(0, headAvail - 112) +
      '\n…[kadasterkern ingekort; onderstaand dossier-/BRP-deel heeft prioriteit]';
  }

  let out = prefix + doss;
  if (out.length > max) {
    out = out.slice(0, max - 80) + '\n…[afgekapt voor burgerlijke-prompt]';
