  let allPaired = gehuwdKlanten.length > 0;
  for (const g of gehuwdKlanten) {
    const gName = g?.naam_hoofdletters || g?.volledige_naam || g?.naam || '';
    if (!tokens(gName).length) { allPaired = false; break; }
    const partners = klanten.filter((k) => {
      if (k === g) return false;
      const n = k?.naam_hoofdletters || k?.volledige_naam || k?.naam || '';
      return shareToken(gName, n);
    });
    if (partners.length === 0) { allPaired = false; break; }
  }
  if (allPaired) {
    normalised = normalised.filter((ap) => {
      const id = String(ap.id || '').toLowerCase();
      const titel = String(ap.titel || '').toLowerCase();
      const actie = String(ap.actie || '').toLowerCase();
      const isToestemmingTopic =
        /toestemming/.test(id) ||
        /toestemming/.test(titel) ||
        /meetekening|meetekenen/.test(titel) ||
        /toestemming|meeteken/.test(actie) ||
        /art\.?\s*1:88/.test(String(ap.juridisch_kader || ''));
      return !isToestemmingTopic;
    });
  }
} catch (_) {}

